    # src/databricks/labs/community_connector/sources/gmail/gmail.py
    ########################################################

    def _parse_max_per_batch(table_options: Dict[str, str] | None) -> int:
        if not table_options:
            return 0
        raw = table_options.get("max_records_per_batch")
        if raw is None:
            return 0
        try:
            value = int(raw)
        except (TypeError, ValueError):
            return 0
        return value if value > 0 else 0


    class GmailLakeflowConnect(LakeflowConnect, SupportsIngestionAgent):
        """Gmail connector implementing the LakeflowConnect interface with 100% API coverage."""

        def __init__(self, options: dict[str, str]) -> None:
            """
            Initialize the Gmail connector with a pre-issued OAuth access token.

            The Unity Catalog COMMUNITY connection (``community_oauth_flow=u2m``
            or ``u2m_per_user``) owns the OAuth dance — Databricks performs the
            authorization-code exchange (and per-user refresh in u2m_per_user
            mode) and hands the connector a valid bearer token at query time.
            The connector treats it as opaque: no client_id/secret, no refresh,
            no token endpoint. A 401 mid-query means the token expired or was
            revoked; the user re-authorizes through the CLI.

            Expected options:
                - access_token: OAuth 2.0 bearer token (Gmail + Drive scopes)
                - user_id (optional): user email or 'me' (default: 'me')
            """
            self.access_token = options.get("access_token")
            self.user_id = options.get("user_id", "me")

            if not self.access_token:
                raise ValueError(
                    "Gmail connector requires 'access_token' in options. "
                    "Configure the Unity Catalog connection as TYPE COMMUNITY "
                    "with community_oauth_flow=u2m or u2m_per_user; the OAuth "
                    "exchange runs at connection-creation time and the access "
                    "token is injected into connector options at query time."
                )

            self.api = GmailApiClient(self.access_token, self.user_id)

            # Snapshot the mailbox historyId at init time. Gmail's mailbox
            # historyId advances on every write (new mail, reads, label edits),
            # so without an init-time cap, _read_messages_incremental would keep
            # returning a higher offset every microbatch on an active mailbox
            # and Trigger.AvailableNow would never terminate. The next pipeline
            # update creates a fresh source and picks up a new snapshot.
            profile = self.api.make_request(
                "GET", f"/users/{self.user_id}/profile",
            )
            self._init_history_id = profile.get("historyId") if profile else None

        # ─── Interface Methods ────────────────────────────────────────────────────

        def list_tables(self) -> list[str]:
            """Return the list of available Gmail tables."""
            return SUPPORTED_TABLES.copy()

        def agent_operations(self):
            """Expose Gmail-specific agent operations on top of the framework built-ins.

            Replaces ``preview_table`` with a filter-aware variant and adds
            ``search_messages``, ``get_message``, ``list_attachments``,
            ``download_attachment``. See ``gmail_agent_ops`` for details.
            """
            return build_gmail_agent_operations()

        def get_table_schema(self, table_name: str, table_options: Dict[str, str]) -> StructType:
            """Fetch the schema of a table."""
            self._validate_table(table_name)
            return TABLE_SCHEMAS[table_name]

        def read_table_metadata(self, table_name: str, table_options: Dict[str, str]) -> Dict:
            """Fetch the metadata of a table."""
            self._validate_table(table_name)
            return TABLE_METADATA[table_name]

        def read_table(
            self, table_name: str, start_offset: dict, table_options: Dict[str, str]
        ) -> (Iterator[dict], dict):
            """
            Read records from a table with streaming iteration.

            For messages and threads with a start_offset containing historyId,
            uses the History API for incremental reads. Otherwise, performs
            a full list operation.
            """
            self._validate_table(table_name)

            read_map = {
                "messages": self._read_messages,
                "threads": self._read_threads,
                "labels": self._read_labels,
                "drafts": self._read_drafts,
                "profile": self._read_profile,
                "settings": self._read_settings,
                "filters": self._read_filters,
                "forwarding_addresses": self._read_forwarding_addresses,
                "send_as": self._read_send_as,
                "delegates": self._read_delegates,
            }
            return read_map[table_name](start_offset, table_options)

        def read_table_deletes(
            self, table_name: str, start_offset: dict, table_options: Dict[str, str]
        ) -> (Iterator[dict], dict):
            """
            Read deleted records from Gmail using History API.

            Gmail History API provides messagesDeleted events for tracking deletions.
            This is only applicable for messages and threads (CDC tables).
            """
            self._validate_table(table_name)

            # Only messages and threads support delete tracking
            if table_name not in ("messages", "threads"):
                return iter([]), {}

            start_history_id = start_offset.get("historyId") if start_offset else None
            if not start_history_id:
                return iter([]), {}

            params = {
                "startHistoryId": start_history_id,
                "maxResults": 500,
                "historyTypes": "messageDeleted",
            }

            page_token = None
            latest_history_id = start_history_id
            deleted_records = []
            seen_ids = set()

            while True:
                if page_token:
                    params["pageToken"] = page_token

                response = self.api.make_request("GET", f"/users/{self.user_id}/history", params=params)

                if response is None:
                    break

                if response.get("historyId"):
                    latest_history_id = response["historyId"]

                deleted_records.extend(
                    self._collect_deleted_records(
                        table_name, response.get("history", []), seen_ids, latest_history_id
                    )
                )

                page_token = response.get("nextPageToken")
                if not page_token:
                    break

            # Mirror the _init_history_id cap from the incremental readers so the
            # deletes path also terminates under Trigger.AvailableNow.
            if (
                self._init_history_id
                and int(latest_history_id) > int(self._init_history_id)
            ):
                latest_history_id = str(self._init_history_id)

            next_offset = {"historyId": latest_history_id}
            return iter(deleted_records), next_offset

        def _collect_deleted_records(
            self, table_name: str, history_records: list, seen_ids: set, latest_history_id: str
        ) -> list[dict]:
            """Extract deleted record entries from history records."""
            deleted_records = []
            for history_record in history_records:
                record_history_id = history_record.get("id", latest_history_id)
                for deleted in history_record.get("messagesDeleted", []):
                    msg = deleted.get("message", {})
                    msg_id = msg.get("id")
                    if not msg_id:
                        continue
                    if table_name == "messages" and msg_id not in seen_ids:
                        seen_ids.add(msg_id)
                        deleted_records.append(
                            {
                                "id": msg_id,
                                "threadId": msg.get("threadId"),
                                "historyId": record_history_id,
                            }
                        )
                    elif table_name == "threads":
                        thread_id = msg.get("threadId")
                        if thread_id and thread_id not in seen_ids:
                            seen_ids.add(thread_id)
                            deleted_records.append({"id": thread_id, "historyId": record_history_id})
            return deleted_records

        # ─── Helpers ──────────────────────────────────────────────────────────────

        def _validate_table(self, table_name: str) -> None:
            """Validate that the table is supported."""
            if table_name not in SUPPORTED_TABLES:
                raise ValueError(
                    f"Unsupported table: '{table_name}'. Supported tables are: {SUPPORTED_TABLES}"
                )

        def _pin_to_init_offset(self, latest_history_id) -> Dict[str, str]:
            """Return the next offset, pinned to the init-time historyId snapshot.

            Pinning to ``self._init_history_id`` lets the next microbatch enter
            ``_read_*_incremental`` with ``start == cap`` and short-circuit, so
            Trigger.AvailableNow terminates.  Falls back to the highest
            historyId seen on this drain only when the ``__init__`` profile
            call failed; in that mode termination is best-effort.
            """
            if self._init_history_id:
                return {"historyId": str(self._init_history_id)}
            if latest_history_id:
                return {"historyId": str(latest_history_id)}
            return {}

        # ─── Table Readers ────────────────────────────────────────────────────────

        def _read_messages(
            self, start_offset: dict, table_options: Dict[str, str]
        ) -> (Iterator[dict], dict):
            """Read messages using streaming list + batch get pattern."""
            start_history_id = start_offset.get("historyId") if start_offset else None

            if start_history_id:
                return self._read_messages_incremental(start_history_id, table_options)
            return self._read_messages_streaming(table_options)

        def _read_messages_streaming(
            self,
            table_options: Dict[str, str],
        ) -> (Iterator[dict], dict):
            """Stream messages with sequential fetching for reliability."""
            max_results = int(table_options.get("maxResults", "100"))
            query = table_options.get("q")
            label_ids = table_options.get("labelIds")
            include_spam_trash = table_options.get("includeSpamTrash", "false").lower() == "true"

            params = {"maxResults": min(max_results, 500)}
            if query:
                params["q"] = query
            if label_ids:
                params["labelIds"] = label_ids
            if include_spam_trash:
                params["includeSpamTrash"] = "true"

            state = {"latest_history_id": None}
            format_type = table_options.get("format", "full")

            def fetch_message(mid):
                return self.api.make_request(
                    "GET",
                    f"/users/{self.user_id}/messages/{mid}",
                    {"format": format_type},
                )

            all_messages = []
            page_token = None

            while True:
                if page_token:
                    params["pageToken"] = page_token

                response = self.api.make_request(
                    "GET", f"/users/{self.user_id}/messages", params=params
                )

                if not response or "messages" not in response:
                    break

                message_ids = [m["id"] for m in response.get("messages", [])]

                # Fetch messages in parallel for better performance
                with ThreadPoolExecutor(max_workers=MAX_WORKERS) as executor:
                    results = list(executor.map(fetch_message, message_ids))

                for msg_detail in results:
                    if msg_detail:
                        if msg_detail.get("historyId"):
                            if (
                                not state["latest_history_id"]
                                or int(msg_detail["historyId"]) > int(state["latest_history_id"])
                            ):
                                state["latest_history_id"] = msg_detail["historyId"]
                        all_messages.append(msg_detail)

                page_token = response.get("nextPageToken")
                if not page_token:
                    break

            return iter(all_messages), self._pin_to_init_offset(state["latest_history_id"])

        def _read_messages_incremental(
            self, start_history_id: str, table_options: Dict[str, str]
        ) -> (Iterator[dict], dict):
            """Read messages incrementally using History API with batch fetching."""
            # Already at or past the init-time snapshot — return empty so
            # AvailableNow sees end_offset == start_offset and terminates.
            if (
                self._init_history_id
                and int(start_history_id) >= int(self._init_history_id)
            ):
                return iter([]), {"historyId": str(self._init_history_id)}

            max_per_batch = _parse_max_per_batch(table_options)

            params = {
                "startHistoryId": start_history_id,
                "maxResults": 500,
                "historyTypes": "messageAdded",
            }

            page_token = None
            latest_history_id = start_history_id
            all_message_ids = set()

            while True:
                if page_token:
                    params["pageToken"] = page_token

                response = self.api.make_request("GET", f"/users/{self.user_id}/history", params=params)

                if response is None:
                    return self._read_messages_streaming(table_options)

                if response.get("historyId"):
                    latest_history_id = response["historyId"]

                for history_record in response.get("history", []):
                    for added in history_record.get("messagesAdded", []):
                        msg_id = added.get("message", {}).get("id")
                        if msg_id:
                            all_message_ids.add(msg_id)

                if max_per_batch and len(all_message_ids) >= max_per_batch:
                    break
                page_token = response.get("nextPageToken")
                if not page_token:
                    break

            all_messages = []
            message_ids = list(all_message_ids)
            format_type = table_options.get("format", "full")

            for i in range(0, len(message_ids), BATCH_SIZE):
                batch_ids = message_ids[i : i + BATCH_SIZE]
                endpoints = [f"/users/{self.user_id}/messages/{mid}" for mid in batch_ids]
                params_list = [{"format": format_type}] * len(batch_ids)

                batch_results = self.api.make_batch_request(endpoints, params_list)
                all_messages.extend([r for r in batch_results if r])

            # Cap the cursor at the init-time snapshot. Gmail's History API returns
            # the *current* mailbox historyId in `response.historyId`, which advances
            # on every mailbox write. Without this cap, an active mailbox would keep
            # producing strictly higher offsets and AvailableNow would never terminate.
            if (
                self._init_history_id
                and int(latest_history_id) > int(self._init_history_id)
            ):
                latest_history_id = str(self._init_history_id)

            next_offset = {"historyId": latest_history_id}
            return iter(all_messages), next_offset

        def _read_threads(
            self, start_offset: dict, table_options: Dict[str, str]
        ) -> (Iterator[dict], dict):
            """Read threads using streaming list + batch get pattern."""
            start_history_id = start_offset.get("historyId") if start_offset else None

            if start_history_id:
                return self._read_threads_incremental(start_history_id, table_options)
            return self._read_threads_streaming(table_options)

        def _read_threads_streaming(
            self,
            table_options: Dict[str, str],
        ) -> (Iterator[dict], dict):
            """Stream threads with parallel fetching for performance."""
            max_results = int(table_options.get("maxResults", "100"))
            query = table_options.get("q")
            label_ids = table_options.get("labelIds")
            include_spam_trash = table_options.get("includeSpamTrash", "false").lower() == "true"

            params = {"maxResults": min(max_results, 500)}
            if query:
                params["q"] = query
            if label_ids:
                params["labelIds"] = label_ids
            if include_spam_trash:
                params["includeSpamTrash"] = "true"

            state = {"latest_history_id": None}
            all_threads = []
            page_token = None
            format_type = table_options.get("format", "full")

            def fetch_thread(tid):
                return self.api.make_request(
                    "GET",
                    f"/users/{self.user_id}/threads/{tid}",
                    {"format": format_type},
                )

            while True:
                if page_token:
                    params["pageToken"] = page_token

                response = self.api.make_request("GET", f"/users/{self.user_id}/threads", params=params)

                if not response or "threads" not in response:
                    break

                thread_ids = [t["id"] for t in response.get("threads", [])]

                # Fetch threads in parallel for better performance
                with ThreadPoolExecutor(max_workers=MAX_WORKERS) as executor:
                    results = list(executor.map(fetch_thread, thread_ids))

                for thread_detail in results:
                    if thread_detail:
                        if thread_detail.get("historyId"):
                            if (
                                not state["latest_history_id"]
                                or int(thread_detail["historyId"]) > int(state["latest_history_id"])
                            ):
                                state["latest_history_id"] = thread_detail["historyId"]
                        all_threads.append(thread_detail)

                page_token = response.get("nextPageToken")
                if not page_token:
                    break

            return iter(all_threads), self._pin_to_init_offset(state["latest_history_id"])

        def _read_threads_incremental(
            self, start_history_id: str, table_options: Dict[str, str]
        ) -> (Iterator[dict], dict):
            """Read threads incrementally using History API."""
            # Already at or past the init-time snapshot — return empty so
            # AvailableNow sees end_offset == start_offset and terminates.
            if (
                self._init_history_id
                and int(start_history_id) >= int(self._init_history_id)
            ):
                return iter([]), {"historyId": str(self._init_history_id)}

            max_per_batch = _parse_max_per_batch(table_options)

            params = {
                "startHistoryId": start_history_id,
                "maxResults": 500,
                "historyTypes": "messageAdded",
            }

            page_token = None
            latest_history_id = start_history_id
            all_thread_ids = set()

            while True:
                if page_token:
                    params["pageToken"] = page_token

                response = self.api.make_request("GET", f"/users/{self.user_id}/history", params=params)

                if response is None:
                    return self._read_threads_streaming(table_options)

                if response.get("historyId"):
                    latest_history_id = response["historyId"]

                for history_record in response.get("history", []):
                    for added in history_record.get("messagesAdded", []):
                        thread_id = added.get("message", {}).get("threadId")
                        if thread_id:
                            all_thread_ids.add(thread_id)

                if max_per_batch and len(all_thread_ids) >= max_per_batch:
                    break
                page_token = response.get("nextPageToken")
                if not page_token:
                    break

            all_threads = []
            thread_ids = list(all_thread_ids)
            format_type = table_options.get("format", "full")

            for i in range(0, len(thread_ids), BATCH_SIZE):
                batch_ids = thread_ids[i : i + BATCH_SIZE]
                endpoints = [f"/users/{self.user_id}/threads/{tid}" for tid in batch_ids]
                params_list = [{"format": format_type}] * len(batch_ids)

                batch_results = self.api.make_batch_request(endpoints, params_list)
                all_threads.extend([r for r in batch_results if r])

            # Cap at init-time snapshot — see _read_messages_incremental.
            if (
                self._init_history_id
                and int(latest_history_id) > int(self._init_history_id)
            ):
                latest_history_id = str(self._init_history_id)

            next_offset = {"historyId": latest_history_id}
            return iter(all_threads), next_offset

        def _read_labels(
            self, start_offset: dict, table_options: Dict[str, str]
        ) -> (Iterator[dict], dict):
            """Read all labels (snapshot mode)."""
            response = self.api.make_request("GET", f"/users/{self.user_id}/labels")

            if not response or "labels" not in response:
                return iter([]), {}

            # Get basic label list first
            labels = response.get("labels", [])

            # Fetch full details for each label to get counts and colors
            all_labels = []
            for label in labels:
                label_id = label.get("id")
                if label_id:
                    detail = self.api.make_request("GET", f"/users/{self.user_id}/labels/{label_id}")
                    if detail:
                        all_labels.append(detail)
                    else:
                        # Fallback to basic info if detail fetch fails
                        all_labels.append(label)

            return iter(all_labels), {}

        def _read_drafts(
            self, start_offset: dict, table_options: Dict[str, str]
        ) -> (Iterator[dict], dict):
            """Read all drafts (snapshot mode) with parallel fetching."""
            params = {"maxResults": int(table_options.get("maxResults", "100"))}

            all_drafts = []
            page_token = None
            format_type = table_options.get("format", "full")

            while True:
                if page_token:
                    params["pageToken"] = page_token

                response = self.api.make_request("GET", f"/users/{self.user_id}/drafts", params=params)

                if not response or "drafts" not in response:
                    break

                draft_ids = [d["id"] for d in response.get("drafts", [])]

                # Fetch drafts in parallel for better performance
                def fetch_draft(draft_id):
                    return self.api.make_request(
                        "GET",
                        f"/users/{self.user_id}/drafts/{draft_id}",
                        {"format": format_type},
                    )

                with ThreadPoolExecutor(max_workers=MAX_WORKERS) as executor:
                    results = list(executor.map(fetch_draft, draft_ids))
                    all_drafts.extend([r for r in results if r])

                page_token = response.get("nextPageToken")
                if not page_token:
                    break

            return iter(all_drafts), {}

        def _read_profile(
            self, start_offset: dict, table_options: Dict[str, str]
        ) -> (Iterator[dict], dict):
            """Read user profile (single record)."""
            response = self.api.make_request("GET", f"/users/{self.user_id}/profile")

            if not response:
                return iter([]), {}

            return iter([response]), {}

        def _read_settings(
            self, start_offset: dict, table_options: Dict[str, str]
        ) -> (Iterator[dict], dict):
            """Read all user settings combined into a single record."""
            # Fetch all settings in parallel
            endpoints = [
                f"/users/{self.user_id}/settings/autoForwarding",
                f"/users/{self.user_id}/settings/imap",
                f"/users/{self.user_id}/settings/pop",
                f"/users/{self.user_id}/settings/language",
                f"/users/{self.user_id}/settings/vacation",
            ]

            results = self.api.make_batch_request(endpoints)

            # Get email address from profile
            profile = self.api.make_request("GET", f"/users/{self.user_id}/profile")
            email_address = profile.get("emailAddress", self.user_id) if profile else self.user_id

            # Combine all settings into one record
            settings = {
                "emailAddress": email_address,
                "autoForwarding": results[0] if len(results) > 0 else None,
                "imap": results[1] if len(results) > 1 else None,
                "pop": results[2] if len(results) > 2 else None,
                "language": results[3] if len(results) > 3 else None,
                "vacation": results[4] if len(results) > 4 else None,
            }

            return iter([settings]), {}

        def _read_filters(
            self, start_offset: dict, table_options: Dict[str, str]
        ) -> (Iterator[dict], dict):
            """Read all email filters."""
            response = self.api.make_request("GET", f"/users/{self.user_id}/settings/filters")

            if not response or "filter" not in response:
                return iter([]), {}

            return iter(response.get("filter", [])), {}

        def _read_forwarding_addresses(
            self, start_offset: dict, table_options: Dict[str, str]
        ) -> (Iterator[dict], dict):
            """Read all forwarding addresses."""
            response = self.api.make_request(
                "GET", f"/users/{self.user_id}/settings/forwardingAddresses"
            )

            if not response or "forwardingAddresses" not in response:
                return iter([]), {}

            return iter(response.get("forwardingAddresses", [])), {}

        def _read_send_as(
            self, start_offset: dict, table_options: Dict[str, str]
        ) -> (Iterator[dict], dict):
            """Read all send-as aliases."""
            response = self.api.make_request("GET", f"/users/{self.user_id}/settings/sendAs")

            if not response or "sendAs" not in response:
                return iter([]), {}

            return iter(response.get("sendAs", [])), {}

        def _read_delegates(
            self, start_offset: dict, table_options: Dict[str, str]
        ) -> (Iterator[dict], dict):
            """Read all delegates."""
            response = self.api.make_request("GET", f"/users/{self.user_id}/settings/delegates")

            if not response or "delegates" not in response:
                return iter([]), {}

            return iter(response.get("delegates", [])), {}


    ########################################################
    # src/databricks/labs/community_connector/sparkpds/ingestion_agent_datasource.py
    ########################################################

    OPERATION = "operation"
    PARENT = "parent"
    SEARCH = "search"
    PATH = "path"
    NAME = "name"
    METADATA_KEY = "metadataKey"
    TABLE_NAME = "tableName"
    CATALOG_NAME = "catalogName"
    SCHEMA_NAME = "schemaName"
    LIMIT = "limit"

    DEFAULT_PREVIEW_LIMIT = 100

    # Built-in operation names exposed for callers and tests.
    OP_LIST_OBJECTS = "list_objects"
    OP_PREVIEW_TABLE = "preview_table"
    OP_GET_OBJECT_METADATA = "get_object_metadata"
    OP_VALIDATE_CONNECTION = "validate_connection"
    OP_LIST_OPERATIONS = "list_operations"

    # Operation kinds.
    KIND_METADATA = "metadata"
    KIND_DATA = "data"

    # Operations that can dispatch even when the connector failed to build
    # (e.g. bad creds). Today this is only `list_operations` — it can yield
    # the framework's built-in catalog without touching the connector.
    _CONNECTOR_OPTIONAL_OPS = frozenset({OP_LIST_OPERATIONS})


    def _requires_connector(op: AgentOperation) -> bool:
        return op.name not in _CONNECTOR_OPTIONAL_OPS

    # Reserved keys the agent layer owns. Stripped from the dict passed into
    # LakeflowConnect.__init__ so the connector can't accidentally interpret an
    # agent option as one of its own. The user's request options keep these
    # keys; ops read them via the AgentOperation.pull options dict.
    _AGENT_RESERVED_KEYS = frozenset(
        {OPERATION, PARENT, SEARCH, PATH, NAME, METADATA_KEY, LIMIT}
    )


    def _agent_options(options: Mapping[str, str]) -> dict:
        """Options visible to ``AgentOperation.pull`` / ``resolve_schema``.

        Strips only the framework-owned ``operation`` key.
        """
        return {k: v for k, v in options.items() if k != OPERATION}


    def connector_options(options: Mapping[str, str]) -> dict:
        """Options passed to ``LakeflowConnect.__init__`` and to read-side calls
        (``read_table``, ``get_table_schema``, ``read_table_metadata``).

        Strips ``operation`` plus the agent-reserved keys so the connector sees
        only its own option namespace.
        """
        return {k: v for k, v in options.items() if k not in _AGENT_RESERVED_KEYS}


    # ---------------------------------------------------------------------------
    # Schemas
    # ---------------------------------------------------------------------------

    _META_STRUCT = StructType(
        [
            StructField("status", StringType(), False),
            StructField("code", StringType(), True),
            StructField("message", StringType(), True),
        ]
    )


    def _meta_field(nullable: bool) -> StructField:
        return StructField("_meta", _META_STRUCT, nullable)


    _LIST_OBJECTS_BASE_SCHEMA = StructType(
        [
            StructField("name", StringType(), True),
            StructField("type", StringType(), True),
            StructField("full_path", StringType(), True),
        ]
    )

    _GET_OBJECT_METADATA_BASE_SCHEMA = StructType(
        [
            StructField("key", StringType(), True),
            StructField("value", StringType(), True),
        ]
    )

    _VALIDATE_CONNECTION_BASE_SCHEMA = StructType([])

    _LIST_OPERATIONS_BASE_SCHEMA = StructType(
        [
            StructField("name", StringType(), False),
            StructField("description", StringType(), True),
            StructField("kind", StringType(), True),
            StructField("result_schema_json", StringType(), True),
            StructField("parameters_json", StringType(), True),
        ]
    )


    def _meta(
        status: str = "ok",
        code: Optional[str] = None,
        message: Optional[str] = None,
    ) -> dict:
        return {"status": status, "code": code, "message": message}


    def _error_str(exc: BaseException) -> str:
        return f"{type(exc).__name__}: {exc}"


    # ---------------------------------------------------------------------------
    # Built-in AgentOperation subclasses.
    #
    # Each fixes ``name``, ``description``, ``kind``, ``schema`` and ``pull``.
    # ``pull`` parses the request options into typed kwargs and delegates to
    # ``produce`` — the single override point for sources that want a richer
    # implementation. ``produce`` is the only method a source customising a
    # built-in should override.
    # ---------------------------------------------------------------------------

    class ListObjectsOp(AgentOperation):
        """Built-in: hierarchical listing of objects under an optional parent."""

        name = OP_LIST_OBJECTS
        description = (
            "Hierarchical listing of objects. Returns rows of (name, type, full_path)."
        )
        kind = KIND_METADATA
        schema = _LIST_OBJECTS_BASE_SCHEMA
        parameters = (
            Parameter(
                name=PARENT,
                description="Path identifying the parent to list under. "
                "Empty/missing lists from the source root.",
            ),
            Parameter(
                name=SEARCH,
                description="Regex filter applied to result names.",
            ),
        )

        def pull(self, connector, options):
            parent = options.get(PARENT) or None
            search = options.get(SEARCH) or None
            return self.produce(connector, parent=parent, search=search)

        def produce(
            self,
            connector: LakeflowConnect,
            *,
            parent: Optional[str],
            search: Optional[str],
        ) -> Iterable[Mapping[str, Any]]:
            """Yield rows of ``(name, type, full_path)``.

            Default flat listing derived from ``list_tables``. Override to
            return hierarchical results or to bind to a source-native
            listing API.
            """
            return _default_list_objects(connector, parent, search)


    class GetObjectMetadataOp(AgentOperation):
        """Built-in: per-object metadata as ``(key, value)`` rows."""

        name = OP_GET_OBJECT_METADATA
        description = "Per-object metadata as (key, value) rows."
        kind = KIND_METADATA
        schema = _GET_OBJECT_METADATA_BASE_SCHEMA
        parameters = (
            Parameter(name=NAME, required=True, description="Object name to describe."),
            Parameter(name=PATH, description="Path of the parent (e.g. namespace)."),
            Parameter(
                name=METADATA_KEY,
                description="If set, return only this specific metadata key.",
            ),
        )

        def pull(self, connector, options):
            name = options[NAME]  # framework validated required.
            path = options.get(PATH) or None
            metadata_key = options.get(METADATA_KEY) or None
            return self.produce(
                connector,
                path=path,
                name=name,
                metadata_key=metadata_key,
                table_options=connector_options(options),
            )

        def produce(
            self,
            connector: LakeflowConnect,
            *,
            path: Optional[str],
            name: str,
            metadata_key: Optional[str],
            table_options: Mapping[str, str],
        ) -> Iterable[Mapping[str, Any]]:
            """Yield ``(key, value)`` rows describing the named object.

            Default flattens ``read_table_metadata`` and maps connector
            keys to the standard ingestion-agent vocabulary
            (``primary_key`` from ``primary_keys``, ``cursor_column`` from
            ``cursor_field``).
            """
            del path
            return _default_get_object_metadata(
                connector,
                table_name=name,
                table_options=table_options,
                metadata_key=metadata_key,
            )


    class PreviewTableOp(AgentOperation):
        """Built-in: sample-read a tabular object.

        Data-kind — rows pass through with the table's natural schema (no
        ``_meta`` column) and errors surface as Spark exceptions. Override
        :meth:`produce` to wire to a source-native sampling API.
        """

        name = OP_PREVIEW_TABLE
        description = "Sample a tabular object. Returns the table's natural schema and rows."
        kind = KIND_DATA
        parameters = (
            Parameter(name=TABLE_NAME, required=True, description="Table to sample."),
            Parameter(
                name=CATALOG_NAME,
                description="Catalog qualifier when the source supports it.",
            ),
            Parameter(
                name=SCHEMA_NAME,
                description="Schema qualifier when the source supports it.",
            ),
            Parameter(
                name=LIMIT,
                type="integer",
                default=DEFAULT_PREVIEW_LIMIT,
                description=f"Maximum rows to return (default {DEFAULT_PREVIEW_LIMIT}).",
            ),
        )

        def resolve_schema(self, connector, options):
            table_name = options[TABLE_NAME]
            return connector.get_table_schema(table_name, connector_options(options))

        def pull(self, connector, options):
            table_name = options[TABLE_NAME]
            limit = _int_option(options, LIMIT, DEFAULT_PREVIEW_LIMIT)
            table_options = connector_options(options)
            records = self.produce(
                connector,
                table_name=table_name,
                limit=limit,
                table_options=table_options,
            )
            # Framework-side cap. Defends against an override that ignores `limit`.
            return itertools.islice(records, limit)

        def produce(
            self,
            connector: LakeflowConnect,
            *,
            table_name: str,
            limit: int,
            table_options: Mapping[str, str],
        ) -> Iterable[Mapping[str, Any]]:
            """Yield up to ``limit`` records from ``table_name``.

            Default consumes ``read_table`` and lets the framework slice.
            Override to use a source-native LIMIT clause when available.
            """
            del limit
            return _default_preview_records(connector, table_name, table_options)


    class ValidateConnectionOp(AgentOperation):
        """Built-in: connection-level health check.

        Returns one row with the standard ``_meta`` struct. Override
        :meth:`produce` to use a source-native ping; the default attempts
        ``connector.list_tables()`` and reports any raised exception.
        """

        name = OP_VALIDATE_CONNECTION
        description = (
            "Connection-level health check. Returns one row with _meta only."
        )
        kind = KIND_METADATA
        schema = _VALIDATE_CONNECTION_BASE_SCHEMA

        def pull(self, connector, options):
            del options
            return [{"_meta": _normalize_meta(self.produce(connector))}]

        def produce(self, connector: LakeflowConnect) -> Mapping[str, Optional[str]]:
            """Return ``{status, code, message}`` for the connection.

            Default: try ``list_tables``; report exceptions as ``error``.
            """
            try:
                connector.list_tables()
            except Exception as exc:  # pylint: disable=broad-except
                return _meta(
                    status="error",
                    code=type(exc).__name__,
                    message=_error_str(exc),
                )
            return _meta(status="ok")


    class ListOperationsOp(AgentOperation):
        """Built-in: list operations supported by this connection.

        Framework-owned. Runs even when the connector failed to build —
        returns the framework's built-in catalog, minus any source-defined
        operations the connector would have contributed. Each row carries
        the schema and parameter metadata an agent needs to plan a call.
        """

        name = OP_LIST_OPERATIONS
        description = (
            "List operations supported by this connection, with their "
            "parameter declarations and result schemas."
        )
        kind = KIND_METADATA
        schema = _LIST_OPERATIONS_BASE_SCHEMA

        def pull(self, connector, options):
            del options
            for op in _resolve_operation_catalog(connector).values():
                yield {
                    "name": op.name,
                    "description": op.description,
                    "kind": op.kind,
                    "result_schema_json": op.schema.json() if op.schema is not None else None,
                    "parameters_json": _parameters_to_json(getattr(op, "parameters", ())),
                }


    # Ordered map of built-in operations. Source-defined operations with the same
    # name replace these (see :func:`_resolve_operation_catalog`).
    _BUILTIN_OPERATIONS: dict[str, AgentOperation] = {
        op.name: op
        for op in (
            ListObjectsOp(),
            PreviewTableOp(),
            GetObjectMetadataOp(),
            ValidateConnectionOp(),
            ListOperationsOp(),
        )
    }


    # ---------------------------------------------------------------------------
    # Dispatcher (plain class, not a DataSource)
    # ---------------------------------------------------------------------------

    # pylint: disable=invalid-name,missing-function-docstring
    class IngestionAgentDispatcher:
        """Dispatches ingestion-agent operations onto a pre-built connector.

        Constructed by :class:`LakeflowSource` when the ``operation`` option
        is set. The connector is built by ``LakeflowSource`` and passed in
        — the dispatcher never instantiates it itself.

        - ``schema()`` resolves the operation and asks it for its schema.
          Metadata-kind ops automatically include a ``_meta`` column;
          data-kind ops return the schema unchanged.
        - ``reader()`` returns an :class:`IngestionAgentReader` that
          applies ``_meta`` defaults and converts errors to a single
          error row (metadata kind) or lets them propagate (data kind).

        Init-error policy: when the connector failed to build, ``connector``
        is ``None`` and ``init_error`` holds the exception. The reader uses
        the operation's :attr:`AgentOperation.requires_connector` flag —
        ops that don't need a connector (e.g. ``list_operations``) still
        run; metadata-kind ops that do need one emit an error row;
        data-kind ops re-raise.
        """

        def __init__(
            self,
            options: Mapping[str, str],
            connector: Optional[LakeflowConnect],
            init_error: Optional[BaseException] = None,
        ) -> None:
            self.options = dict(options)
            self.connector = connector
            self.init_error = init_error
            self.operation_name = self.options.get(OPERATION)
            if not self.operation_name:
                raise ValueError(
                    f"ingestion-agent dispatch requires an '{OPERATION}' option."
                )
            self.operation = _resolve_operation(connector, self.operation_name)

        def schema(self) -> StructType:
            if self.operation is None:
                raise ValueError(
                    f"Unknown ingestion-agent operation: {self.operation_name}"
                )
            # If the connector failed to init and the op needs it, we can't
            # safely call resolve_schema (it may dereference the connector).
            # Fall back to the op's static `schema` attribute and rely on the
            # reader to emit an error row. Data-kind ops in this state can't
            # produce a valid schema at all, so we raise the init error.
            if self.init_error is not None and _requires_connector(self.operation):
                if self.operation.kind == KIND_DATA:
                    raise self.init_error
                base = self.operation.schema or StructType([])
            else:
                # Data-kind ops compute their schema from request options
                # (e.g. preview_table needs `tableName`). Validate required
                # parameters now so resolve_schema doesn't trip over missing
                # keys. Metadata-kind ops use a static schema; their parameter
                # validation runs at read time and surfaces as an error row.
                if self.operation.kind == KIND_DATA:
                    _validate_required_parameters(self.operation, self.options)
                base = self.operation.resolve_schema(self.connector, self.options)
            if self.operation.kind == KIND_METADATA:
                # Metadata-kind ops emit a single error row carrying only _meta
                # when pull() raises. Relax data-column nullability so that
                # error row validates against the schema.
                return _ensure_meta_field(_relax_nullability(base))
            return base

        def reader(self, schema: StructType) -> "IngestionAgentReader":
            return IngestionAgentReader(
                options=self.options,
                schema=schema,
                operation=self.operation,
                operation_name=self.operation_name,
                connector=self.connector,
                init_error=self.init_error,
            )


    # ---------------------------------------------------------------------------
    # Reader
    # ---------------------------------------------------------------------------

    class IngestionAgentReader(DataSourceReader):
        def __init__(
            self,
            options: Mapping[str, str],
            schema: StructType,
            operation: Optional[AgentOperation],
            operation_name: str,
            connector: Optional[LakeflowConnect],
            init_error: Optional[BaseException],
        ) -> None:
            self.options = dict(options)
            self.schema = schema
            self.operation = operation
            self.operation_name = operation_name
            self.connector = connector
            self.init_error = init_error

        def partitions(self):
            # All ingestion-agent operations are small, single-partition reads.
            return [InputPartition(None)]

        def read(self, _partition):
            if self.operation is None:
                yield from self._yield_error_rows(
                    ValueError(
                        f"Unknown ingestion-agent operation: {self.operation_name}"
                    )
                )
                return

            # If the connector failed and this op needs it, route by kind:
            # metadata-kind → error row, data-kind → re-raise.
            if self.init_error is not None and _requires_connector(self.operation):
                if self.operation.kind == KIND_METADATA:
                    yield from self._yield_error_rows(self.init_error)
                    return
                raise self.init_error

            request_options = _agent_options(self.options)

            if self.operation.kind == KIND_DATA:
                # Data-kind ops surface exceptions as Spark exceptions and don't
                # carry a _meta column.
                for record in self.operation.pull(self.connector, request_options):
                    yield parse_value(record, self.schema)
                return

            # Metadata-kind: framework wraps pull() exceptions into a single
            # error row and setdefaults _meta on every row to {status: ok}.
            try:
                _validate_required_parameters(self.operation, request_options)
                rows = self.operation.pull(self.connector, request_options)
                # Materialise so generator-time errors are caught and converted to
                # a single error row instead of escaping mid-iteration. Acceptable
                # because all metadata ops produce small results.
                rows = list(rows) if not isinstance(rows, list) else rows
            except Exception as exc:  # pylint: disable=broad-except
                rows = [self._error_row(exc)]
            for row in rows:
                yield parse_value(_with_default_meta(row), self.schema)

        def _yield_error_rows(self, exc: BaseException):
            yield parse_value(_with_default_meta(self._error_row(exc)), self.schema)

        def _error_row(self, exc: BaseException) -> dict:
            if isinstance(exc, AgentError):
                code = exc.code
                message = str(exc)
            elif isinstance(exc, ValueError):
                # Framework-detected input errors (legacy code paths still raise
                # ValueError for missing options).
                code = ErrorCode.BAD_REQUEST
                message = str(exc)
            else:
                code = ErrorCode.INTERNAL_ERROR
                message = _error_str(exc)
            return {"_meta": _meta(status="error", code=code, message=message)}


    # ---------------------------------------------------------------------------
    # Operation catalog
    # ---------------------------------------------------------------------------

    def _source_operations(
        connector: Optional[LakeflowConnect],
    ) -> Mapping[str, AgentOperation]:
        if not isinstance(connector, SupportsIngestionAgent):
            return {}
        try:
            ops = connector.agent_operations()
        except Exception:  # pylint: disable=broad-except
            return {}
        if not ops:
            return {}
        out: dict[str, AgentOperation] = {}
        for op_name, op in ops.items():
            if not isinstance(op, AgentOperation):
                raise TypeError(
                    f"agent_operations()[{op_name!r}] must be an AgentOperation "
                    f"instance, got {type(op).__name__}."
                )
            out[op_name] = op
        return out


    def _resolve_operation_catalog(
        connector: Optional[LakeflowConnect],
    ) -> Mapping[str, AgentOperation]:
        """Built-ins plus source-defined operations.

        Source-defined entries replace built-ins with the same name. Ordering:
        built-ins first (canonical order), then any new source-defined
        operations (sorted by name for determinism).
        """
        source_ops = _source_operations(connector)
        catalog: dict[str, AgentOperation] = {}
        for name, op in _BUILTIN_OPERATIONS.items():
            catalog[name] = source_ops.get(name, op)
        extras = {n: o for n, o in source_ops.items() if n not in _BUILTIN_OPERATIONS}
        for name in sorted(extras):
            catalog[name] = extras[name]
        return catalog


    def _resolve_operation(
        connector: Optional[LakeflowConnect], operation_name: str
    ) -> Optional[AgentOperation]:
        return _resolve_operation_catalog(connector).get(operation_name)


    # ---------------------------------------------------------------------------
    # Helpers
    # ---------------------------------------------------------------------------

    def _required_option(
        options: Mapping[str, str], key: str, operation: str
    ) -> str:
        value = options.get(key)
        if not value:
            raise AgentError(
                ErrorCode.BAD_REQUEST,
                f"Operation '{operation}' requires option '{key}'.",
            )
        return value


    def _int_option(options: Mapping[str, str], key: str, default: int) -> int:
        raw = options.get(key)
        if raw is None or raw == "":
            return default
        try:
            return int(raw)
        except (TypeError, ValueError) as exc:
            raise AgentError(
                ErrorCode.BAD_REQUEST,
                f"Option '{key}' must be an integer, got {raw!r}.",
            ) from exc


    def _validate_required_parameters(
        op: AgentOperation, options: Mapping[str, str]
    ) -> None:
        """Reject calls missing a required :class:`Parameter`.

        Raises :class:`AgentError` with ``bad_request`` when a required
        parameter is absent. Called by the dispatcher before
        ``resolve_schema`` (data-kind) and before ``pull`` (metadata-kind),
        so ops can rely on declared required inputs being present.
        """
        for param in getattr(op, "parameters", ()):
            if param.required and not options.get(param.name):
                raise AgentError(
                    ErrorCode.BAD_REQUEST,
                    f"Operation '{op.name}' requires option '{param.name}'.",
                )


    def _parameters_to_json(params: Iterable[Parameter]) -> str:
        """JSON-serialise a tuple of :class:`Parameter` declarations.

        Surfaced by ``list_operations.parameters_json`` so agents can plan
        calls. Fields with ``None`` default / enum are kept in the JSON for
        a stable schema.
        """
        return json.dumps(
            [
                {
                    "name": p.name,
                    "type": p.type,
                    "description": p.description,
                    "required": p.required,
                    "default": p.default,
                    "enum": list(p.enum) if p.enum else None,
                }
                for p in params
            ]
        )


    def _with_default_meta(row: Mapping[str, Any]) -> dict:
        out = dict(row)
        out.setdefault("_meta", _meta(status="ok"))
        return out


    def _normalize_meta(value: Any) -> dict:
        if value is None:
            return _meta(status="ok")
        if isinstance(value, Mapping):
            return {
                "status": str(value.get("status", "ok")),
                "code": _str_or_none(value.get("code")),
                "message": _str_or_none(value.get("message")),
            }
        raise TypeError(
            f"validate_connection produce() must return a mapping, "
            f"got {type(value).__name__}."
        )


    def _str_or_none(value: Any) -> Optional[str]:
        if value is None:
            return None
        return str(value)


    def _ensure_meta_field(schema: StructType) -> StructType:
        if any(f.name == "_meta" for f in schema.fields):
            return schema
        return StructType(list(schema.fields) + [_meta_field(nullable=True)])


    def _relax_nullability(schema: StructType) -> StructType:
        """Return a copy of ``schema`` with every non-``_meta`` field nullable.

        Used for metadata-kind operations so the framework's error row (which
        carries only ``_meta``) parses cleanly even when the operation
        declared its data columns as non-nullable.
        """
        return StructType(
            [
                StructField(f.name, f.dataType, True, f.metadata)
                if f.name != "_meta"
                else f
                for f in schema.fields
            ]
        )


    # ---------------------------------------------------------------------------
    # Default implementations of the built-in operations
    # ---------------------------------------------------------------------------

    def _default_list_objects(
        connector: LakeflowConnect,
        parent: Optional[str],
        search: Optional[str],
    ) -> Iterator[dict]:
        """Flat listing of ``list_tables()`` — every table at the source root."""
        if parent:
            # The default connector has no hierarchy. A non-empty parent that
            # isn't the source root is treated as "no children" rather than an
            # error so the agent can probe paths without crashing.
            return iter([])
        pattern = re.compile(search) if search else None
        return (
            {"name": name, "type": "table", "full_path": name}
            for name in connector.list_tables()
            if pattern is None or pattern.search(name)
        )


    def _default_get_object_metadata(
        connector: LakeflowConnect,
        table_name: str,
        table_options: Mapping[str, str],
        metadata_key: Optional[str],
    ) -> Iterator[dict]:
        """Flatten ``read_table_metadata`` into ``(key, value)`` rows.

        Maps the connector's metadata keys to the standardised ingestion-agent
        keys (``primary_key`` from ``primary_keys``, ``cursor_column`` from
        ``cursor_field``) and preserves the others verbatim.
        """
        raw = connector.read_table_metadata(table_name, table_options)

        standardized: list[Tuple[str, Any]] = []
        if "primary_keys" in raw:
            standardized.append(("primary_key", raw["primary_keys"]))
        if "cursor_field" in raw:
            standardized.append(("cursor_column", raw["cursor_field"]))
        if "ingestion_type" in raw:
            standardized.append(("ingestion_type", raw["ingestion_type"]))
        seen = {"primary_keys", "cursor_field", "ingestion_type"}
        for key, value in raw.items():
            if key in seen:
                continue
            standardized.append((key, value))

        if metadata_key is not None:
            standardized = [(k, v) for k, v in standardized if k == metadata_key]
            if not standardized:
                return iter([
                    {
                        "key": metadata_key,
                        "value": None,
                        "_meta": _meta(
                            status="warning",
                            code="metadata_key_not_found",
                            message=f"Metadata key '{metadata_key}' is not "
                            f"available for '{table_name}'.",
                        ),
                    }
                ])

        return ({"key": k, "value": _to_str_value(v)} for k, v in standardized)


    def _default_preview_records(
        connector: LakeflowConnect,
        table_name: str,
        table_options: Mapping[str, str],
    ) -> Iterator[Mapping[str, Any]]:
        """Pull records from ``read_table``; the caller slices to the limit."""
        records, _offset = connector.read_table(table_name, None, dict(table_options))
        return records


    def _to_str_value(value: Any) -> Optional[str]:
        if value is None:
            return None
        if isinstance(value, str):
            return value
        if isinstance(value, (list, tuple, dict, set)):
            try:
                return json.dumps(list(value) if isinstance(value, set) else value)
            except (TypeError, ValueError):
                return str(value)
        return str(value)


    ########################################################
    # src/databricks/labs/community_connector/sparkpds/lakeflow_datasource.py
    ########################################################

    LakeflowConnectImpl = GmailLakeflowConnect
    # Constant option or column names
    METADATA_TABLE = "_community_table_metadata"
    NAMESPACES_TABLE = "_community_namespaces"
    TABLES_TABLE = "_community_tables"
    VIRTUAL_TABLES = (METADATA_TABLE, NAMESPACES_TABLE, TABLES_TABLE)
    TABLE_NAME = "tableName"
    TABLE_NAME_LIST = "tableNameList"
    TABLE_CONFIGS = "tableConfigs"
    IS_DELETE_FLOW = "isDeleteFlow"
    NAMESPACE_PREFIX = "namespacePrefix"
    NAMESPACE = "namespace"


    def _decode_list_of_str_option(option_name: str, value: str | None) -> list[str] | None:
        """Decode and validate a JSON-encoded ``list[str]`` Spark option.

        Returns ``None`` if the option is absent; otherwise the parsed list.
        Raises ``ValueError`` with the offending value if the JSON is malformed
        or the decoded value is not a list of strings.
        """
        if value is None:
            return None
        try:
            decoded = json.loads(value)
        except json.JSONDecodeError as e:
            raise ValueError(
                f"option '{option_name}' must be a JSON-encoded list[str]; "
                f"got non-JSON value: {value!r}"
            ) from e
        if not isinstance(decoded, list) or not all(isinstance(s, str) for s in decoded):
            raise ValueError(
                f"option '{option_name}' must be a JSON-encoded list[str]; "
                f"got: {decoded!r}"
            )
        return decoded


    def _decode_dict_option(option_name: str, value: str | None) -> dict:
        """Decode and validate a JSON-encoded ``dict`` Spark option."""
        if value is None:
            return {}
        try:
            decoded = json.loads(value)
        except json.JSONDecodeError as e:
            raise ValueError(
                f"option '{option_name}' must be a JSON-encoded dict; "
                f"got non-JSON value: {value!r}"
            ) from e
        if not isinstance(decoded, dict):
            raise ValueError(
                f"option '{option_name}' must be a JSON-encoded dict; got: {decoded!r}"
            )
        return decoded


    # PySpark's DataSource API requires camelCase method names and inherits
    # semantics from the parent class, so per-method docstrings are redundant.
    # pylint: disable=invalid-name,missing-function-docstring
    class LakeflowStreamReader(SimpleDataSourceStreamReader, SupportsTriggerAvailableNow):
        """
        Implements a data source stream reader for Lakeflow Connect.
        Currently, only the simpleStreamReader is implemented, which uses a
        more generic protocol suitable for most data sources that support
        incremental loading.
        """

        def __init__(
            self,
            options: dict[str, str],
            schema: StructType,
            lakeflow_connect: LakeflowConnect,
        ):
            self.options = options
            self.lakeflow_connect = lakeflow_connect
            self.schema = schema

        def initialOffset(self):
            return {}

        def read(self, start: dict) -> (Iterator[tuple], dict):
            is_delete_flow = self.options.get(IS_DELETE_FLOW) == "true"
            # Strip delete flow options before passing to connector
            table_options = {
                k: v for k, v in self.options.items() if k != IS_DELETE_FLOW
            }

            if is_delete_flow:
                records, offset = self.lakeflow_connect.read_table_deletes(
                    self.options[TABLE_NAME], start, table_options
                )
            else:
                records, offset = self.lakeflow_connect.read_table(
                    self.options[TABLE_NAME], start, table_options
                )
            rows = map(lambda x: parse_value(x, self.schema), records)
            return rows, offset

        def readBetweenOffsets(self, start: dict, end: dict) -> Iterator[tuple]:
            # TODO: This does not ensure the records returned are identical across repeated calls.
            # For append-only tables, the data source must guarantee that reading from the same
            # start offset will always yield the same set of records.
            # For tables ingested as incremental CDC, it is only necessary that no new changes
            # are missed in the returned records.
            return self.read(start)[0]

        def prepareForTriggerAvailableNow(self) -> None:
            # No need to do anything special here. Everything is handled in the __init__ method.
            pass


    class LakeflowPartitionedStreamReader(DataSourceStreamReader, SupportsTriggerAvailableNow):
        """Proxy that bridges SupportsPartitionedStream to PySpark's DataSourceStreamReader.

        Used when a connector implements the SupportsPartitionedStream mixin to
        support partitioned streaming reads across Spark executors.
        """

        def __init__(
            self,
            options: dict[str, str],
            schema: StructType,
            lakeflow_connect: LakeflowConnect,
        ):
            self.options = options
            self.schema = schema
            self.lakeflow_connect = lakeflow_connect
            self.table_name = options[TABLE_NAME]
            self.table_options = {k: v for k, v in options.items() if k != IS_DELETE_FLOW}

        def initialOffset(self):
            return {}

        def getDefaultReadLimit(self):
            # Admission control is the connector's responsibility (e.g. via
            # window_days, max_records_per_batch), not the engine's.  Always
            # ask the engine for ReadAllAvailable.
            return ReadAllAvailable()

        def latestOffset(self, start: dict, limit) -> dict:
            # We declared ReadAllAvailable via getDefaultReadLimit; the engine
            # must respect it.  Anything else means admission-control expectations
            # we do not support — fail loudly rather than silently ignore.
            if not isinstance(limit, ReadAllAvailable):
                raise ValueError(
                    f"LakeflowPartitionedStreamReader only supports ReadAllAvailable; "
                    f"got {type(limit).__name__}. Micro-batch sizing must be controlled "
                    f"by the connector implementation (table_options), not the engine."
                )
            return self.lakeflow_connect.latest_offset(
                self.table_name, self.table_options, start
            )

        def partitions(self, start: dict, end: dict):
            partition_descs = self.lakeflow_connect.get_partitions(
                self.table_name, self.table_options, start, end
            )
            return [InputPartition(json.dumps(p)) for p in partition_descs]

        def read(self, partition: InputPartition):
            partition_desc = json.loads(partition.value)
            records = self.lakeflow_connect.read_partition(
                self.table_name, partition_desc, self.table_options
            )
            return map(lambda x: parse_value(x, self.schema), records)

        def prepareForTriggerAvailableNow(self) -> None:
            # No need to do anything special here. Everything is handled in the __init__ method.
            pass


    class LakeflowBatchReader(DataSourceReader):
        def __init__(
            self,
            options: dict[str, str],
            schema: StructType,
            lakeflow_connect: LakeflowConnect,
        ):
            self.options = options
            self.schema = schema
            self.lakeflow_connect = lakeflow_connect
            self.table_name = options[TABLE_NAME]
            self._supports_partition = isinstance(lakeflow_connect, SupportsPartition)

        def partitions(self):
            if self._supports_partition and self.table_name not in VIRTUAL_TABLES:
                try:
                    partition_descs = self.lakeflow_connect.get_partitions(
                        self.table_name, self.options
                    )
                    return [InputPartition(json.dumps(p)) for p in partition_descs]
                except Exception:
                    self._supports_partition = False
            return [InputPartition(None)]

        def read(self, partition):
            if self.table_name == METADATA_TABLE:
                records = self._read_table_metadata()
            elif self.table_name == NAMESPACES_TABLE:
                records = self._read_namespaces()
            elif self.table_name == TABLES_TABLE:
                records = self._read_tables()
            elif self._supports_partition and partition.value is not None:
                partition_desc = json.loads(partition.value)
                records = self.lakeflow_connect.read_partition(
                    self.table_name, partition_desc, self.options
                )
            else:
                records, _ = self.lakeflow_connect.read_table(self.table_name, None, self.options)
            return map(lambda x: parse_value(x, self.schema), records)

        def _read_table_metadata(self):
            table_names = _decode_list_of_str_option(
                TABLE_NAME_LIST, self.options.get(TABLE_NAME_LIST)
            ) or []
            table_configs = _decode_dict_option(
                TABLE_CONFIGS, self.options.get(TABLE_CONFIGS)
            )
            all_records = []
            # Preserve caller-supplied table order — caller controls it.
            for table in table_names:
                metadata = self.lakeflow_connect.read_table_metadata(
                    table, table_configs.get(table, {})
                )
                all_records.append({TABLE_NAME: table, **metadata})
            return all_records

        def _read_namespaces(self):
            # Connectors without SupportsNamespaces are flat — no rows.
            if not isinstance(self.lakeflow_connect, SupportsNamespaces):
                return []
            prefix = _decode_list_of_str_option(
                NAMESPACE_PREFIX, self.options.get(NAMESPACE_PREFIX)
            )
            namespaces = self.lakeflow_connect.list_namespaces(prefix)
            # Sort framework-side for deterministic output regardless of
            # connector iteration order.
            return [{"namespace": ns} for ns in sorted(namespaces)]

        def _read_tables(self):
            namespace_supplied = NAMESPACE in self.options
            if isinstance(self.lakeflow_connect, SupportsNamespaces):
                if not namespace_supplied:
                    raise ValueError(
                        f"option '{NAMESPACE}' is required when reading "
                        f"'{TABLES_TABLE}' against a connector that implements "
                        f"SupportsNamespaces. Pass a JSON-encoded list[str] "
                        f"(use '[]' for root-level tables; walk the tree via "
                        f"'{NAMESPACES_TABLE}' to enumerate every namespace)."
                    )
                namespace = _decode_list_of_str_option(
                    NAMESPACE, self.options[NAMESPACE]
                )
                tables = self.lakeflow_connect.list_tables_in_namespace(namespace)
                return [
                    {"namespace": namespace, TABLE_NAME: tn}
                    for tn in sorted(tables)
                ]
            # Flat connector path. Reject a stray `namespace` option — the
            # caller probably mistook this connector for namespace-aware and
            # silently ignoring the option would mask the bug.
            if namespace_supplied:
                raise ValueError(
                    f"option '{NAMESPACE}' was supplied but the connector does "
                    f"not implement SupportsNamespaces. Either omit the option "
                    f"or use a namespace-aware connector."
                )
            return [
                {"namespace": [], TABLE_NAME: tn}
                for tn in sorted(self.lakeflow_connect.list_tables())
            ]


    class LakeflowSource(DataSource):
        """
        PySpark DataSource implementation for Lakeflow Connect.
        """

        def __init__(self, options):
            self.options = options
            self._agent_dispatcher: IngestionAgentDispatcher | None = None
            # Agent-operation mode: ``operation`` option routes through the
            # ingestion-agent dispatcher instead of the table read path. The
            # dispatcher owns the option vocabulary and may run even when the
            # connector failed to init (e.g. list_operations), so we build it
            # eagerly and capture any init error.
            if options.get(OPERATION):
                connector: LakeflowConnect | None = None
                init_error: BaseException | None = None
                try:
                    # TEMPORARY: LakeflowConnectImpl is replaced with the actual
                    # implementation class during merge.
                    connector = LakeflowConnectImpl(connector_options(options))  # pylint: disable=abstract-class-instantiated
                except Exception as exc:  # pylint: disable=broad-except
                    init_error = exc
                self._agent_dispatcher = IngestionAgentDispatcher(
                    options=options, connector=connector, init_error=init_error
                )
                self.lakeflow_connect = connector
                return

            table = options.get(TABLE_NAME)
            # Catch typos against the framework's reserved virtual-table namespace
            # early — falling through to the connector with an unknown
            # `_community_*` name yields a confusing per-connector error.
            if table and table.startswith("_community_") and table not in VIRTUAL_TABLES:
                raise ValueError(
                    f"unknown framework virtual table '{table}'. Valid framework "
                    f"virtual tables are: {', '.join(VIRTUAL_TABLES)}. "
                    f"For a regular source table, use a name that does not start "
                    f"with '_community_'."
                )
            # TEMPORARY: LakeflowConnectImpl is replaced with the actual implementation
            # class during merge. See the placeholder comment at the top of this file.
            self.lakeflow_connect = LakeflowConnectImpl(options)  # pylint: disable=abstract-class-instantiated

        @classmethod
        def name(cls):
            return "lakeflow_connect"

        def schema(self):
            if self._agent_dispatcher is not None:
                return self._agent_dispatcher.schema()
            table = self.options[TABLE_NAME]
            if table == METADATA_TABLE:
                return StructType(
                    [
                        StructField(TABLE_NAME, StringType(), False),
                        StructField("primary_keys", ArrayType(StringType()), True),
                        StructField("cursor_field", StringType(), True),
                        StructField("ingestion_type", StringType(), True),
                    ]
                )
            if table == NAMESPACES_TABLE:
                return StructType(
                    [
                        StructField("namespace", ArrayType(StringType()), False),
                    ]
                )
            if table == TABLES_TABLE:
                return StructType(
                    [
                        StructField("namespace", ArrayType(StringType()), False),
                        StructField(TABLE_NAME, StringType(), False),
                    ]
                )
            return self.lakeflow_connect.get_table_schema(table, self.options)

        def reader(self, schema: StructType):
            if self._agent_dispatcher is not None:
                return self._agent_dispatcher.reader(schema)
            return LakeflowBatchReader(self.options, schema, self.lakeflow_connect)

        def streamReader(self, schema: StructType):
            # Use the partitioned DataSourceStreamReader when the connector
            # implements SupportsPartitionedStream and the table opts in.
            # Otherwise, delegate to super() which raises PySparkNotImplementedError,
            # causing Spark to fall back to simpleStreamReader().
            if isinstance(self.lakeflow_connect, SupportsPartitionedStream):
                table = self.options[TABLE_NAME]
                if self.lakeflow_connect.is_partitioned(table):
                    return LakeflowPartitionedStreamReader(self.options, schema, self.lakeflow_connect)
            return super().streamReader(schema)

        def simpleStreamReader(self, schema: StructType):
            return LakeflowStreamReader(self.options, schema, self.lakeflow_connect)


    spark.dataSource.register(LakeflowSource)
